   183→			if len(crdListForGV) == 0 {
   184→				delete(c.specsByGVandName, gv)
   185→			}
   186→			regenerationCounter.With(map[string]string{"group": gv.Group, "version": gv.Version, "crd": name, "reason": "remove"})
