   218→	_, ok := c.specsByGVandName[gv]
   219→	reason := "update"
   220→	if !ok {
   221→		reason = "add"
   222→		c.specsByGVandName[gv] = map[string]*spec3.OpenAPI{}
   223→	}
   224→
   225→	oldSpec, ok := c.specsByGVandName[gv][name]
   226→	if ok {
